export async function seedDatabase() {
  const existingReading = await db.select().from(readingPassages).limit(1);
  if (existingReading.length > 0) return;

  console.log("Seeding database with 100 items per module...");

  for (const topic of readingTopics) {
    const [passage] = await db.insert(readingPassages).values({
      title: topic.title,
      content: topic.content,
      difficulty: topic.difficulty,
      category: topic.category,
      examType: "ielts",
      timeLimit: 15,
    }).returning();

    const questionSet = readingQuestionTemplates.map((qt, idx) => ({
      passageId: passage.id,
      questionText: qt.template(topic.title),
      questionType: "multiple_choice",
      options: qt.options(topic.title),
      correctAnswer: qt.options(topic.title)[qt.correct],
      explanation: `The correct answer relates to the key information presented in the passage about ${topic.title.toLowerCase()}.`,
      order: idx,
    }));

    await db.insert(readingQuestions).values(questionSet);
  }

  for (const topic of listeningTopics) {
    const [passage] = await db.insert(listeningPassages).values({
      title: topic.title,
      transcript: topic.transcript,
      difficulty: topic.difficulty,
      category: topic.category,
      examType: "ielts",
      duration: 180,
    }).returning();

    const questionSet = listeningQuestionTemplates.map((qt, idx) => ({
      passageId: passage.id,
      questionText: qt.template(topic.title),
      questionType: "multiple_choice",
      options: qt.options(topic.title),
      correctAnswer: qt.options(topic.title)[qt.correct],
      explanation: `This answer is supported by the content of the listening passage.`,
      order: idx,
    }));

    await db.insert(listeningQuestions).values(questionSet);
  }

  let writingCount = 0;
  const difficulties = ["Beginner", "Intermediate", "Advanced"];
  for (const group of writingTopicTemplates) {
    for (const topic of group.topics) {
      await db.insert(writingPrompts).values({
        title: `${group.taskType}: ${topic.substring(0, 60)}...`,
        promptText: topic,
        taskType: group.taskType,
        difficulty: difficulties[writingCount % 3],
        examType: "ielts",
        minWords: group.taskType === "Task 1" ? 150 : 250,
        maxWords: group.taskType === "Task 1" ? 200 : 350,
        timeLimit: group.taskType === "Task 1" ? 20 : 40,
      });
      writingCount++;
    }
  }

  let speakingCount = 0;
  for (const group of speakingTopicTemplates) {
    for (const topic of group.topics) {
      await db.insert(speakingPrompts).values({
        title: `${group.taskType}: ${topic.substring(0, 60)}...`,
        promptText: topic,
        taskType: group.taskType,
        difficulty: difficulties[speakingCount % 3],
        examType: "ielts",
        preparationTime: group.taskType === "Part 2" || group.taskType === "Cue Card" ? 60 : 15,
        responseTime: group.taskType === "Part 1" ? 60 : 120,
      });
      speakingCount++;
    }
  }

  console.log(`Seeded: ${readingTopics.length} passages (${readingTopics.length * 4} questions), ${listeningTopics.length} listening passages (${listeningTopics.length * 4} questions), ${writingCount} writing prompts, ${speakingCount} speaking prompts`);
}
